// Extract ESP32 UUID from topic segment [6]:
// Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/<UUID>/telemetry/ble
var uuid = msg.topic.split('/')[6];
if (!uuid || !msg.payload || !msg.payload.mac) return null;

var d = msg.payload;

// Per-beacon timeout — if no update in 10 s (5 missed publishes) mark as lost
var key = uuid + ':' + d.mac;
var timeouts = context.get('timeouts') || {};
if (timeouts[key]) clearTimeout(timeouts[key]);

node.status({ fill: 'green', shape: 'dot', text: d.mac + '  ' + d.dist_m + ' m' });

timeouts[key] = setTimeout(function () {
    node.status({ fill: 'red', shape: 'ring', text: d.mac + ' — lost' });
}, 10000);

context.set('timeouts', timeouts);

msg.uuid   = uuid;
msg.mac    = d.mac;
msg.name   = d.name || '';
msg.rssi   = d.rssi;
msg.dist_m = d.dist_m;
return msg;

finalize:
var timeouts = context.get('timeouts') || {};
Object.keys(timeouts).forEach(function(k) { clearTimeout(timeouts[k]); });
context.set('timeouts', {});

