// Maintain a sorted list of unique device/beacon pairs seen
var known = flow.get('knownBeaconMacs') || [];
var entry = msg.uuid + '/' + msg.mac;

if (known.indexOf(entry) === -1) {
    known.push(entry);
    known.sort();
    flow.set('knownBeaconMacs', known);
}

// Output 1: updated beacon list (overwrites file each time, like UUID logger)
var listMsg = { payload: known.join('\n') };

// Output 2: timestamped CSV row appended to tracking log
var ts = new Date().toISOString();
var csvLine = [ts, msg.uuid, msg.mac, msg.name, msg.rssi, msg.dist_m].join(',') + '\n';
var logMsg = { payload: csvLine };

return [listMsg, logMsg];
